import logging
import redis

log = logging.getLogger("ratelimit")

FAIL_CLOSED_ROUTES = {"/v1/login", "/v1/signup", "/v1/password-reset"}

def check_limit(route, key):
    try:
        return allow(keys=[key], args=bucket_args(route)) == 1
    except redis.RedisError:
        limiter_errors.inc()
        if route in FAIL_CLOSED_ROUTES:
            log.error("limiter down, failing CLOSED for %s", route)
            return False  # abuse here is worse than downtime
        log.warning("limiter down, failing OPEN for %s", route)
        return True  # availability wins for normal API traffic

# 10 MB zone holds ~160k IP states; rate is the steady drain
limit_req_zone $binary_remote_addr zone=api:10m rate=10r/s;

server {
    location /api/ {
        # burst queues spikes; nodelay serves queued requests
        # immediately instead of trickling them out
        limit_req zone=api burst=20 nodelay;
        limit_req_status 429;
        proxy_pass http://app;
    }
}

# Exact-match location wins over /api/ and has no limit_req
location = /healthz {
    access_log off;
    proxy_pass http://app;
}

# Internal CIDRs get an empty key, which disables limiting
geo $limited_ip {
    default        $binary_remote_addr;
    10.0.0.0/8     "";   # cluster-internal traffic
}
limit_req_zone $limited_ip zone=api:10m rate=10r/s;
